function ResultCard({ prediction }) {
  if (!prediction) return null;

  return (
    <div className="result-card">
      <h2>Prediction Result</h2>
      <p>
        Predicted Weight: <strong>{prediction} g</strong>
      </p>
    </div>
  );
}

export default ResultCard;
